    HighlightLast,

    /// The next item is highlighted.
    HighlightNext,

    /// The previous item is highlighted.
    HighlightPrev,

    /// The combobox is dismissed.
    Dismiss,

    /// The combobox is clicked outside.
    ClickOutside,

    /// The combobox is cleared.
    Clear,

