/// Machine for the Autocomplete component.
#[derive(Debug)]
pub struct Machine;

impl ars_core::Machine for Machine {
    type State = State;
    type Event = Event;
    type Context = Context;
    type Props = Props;
    type Messages = Messages;
    type Effect = Effect;
    type Api<'a> = Api<'a>;

    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context) {
        let ids = ComponentIds::from_id(&props.id);
        let collection_id = if props.collection_id.is_empty() {
            ids.part("content")
        } else {
            props.collection_id.clone()
        };
        let input_value = props
            .input_value
            .clone()
            .unwrap_or_else(|| props.default_input_value.clone());
        let mut ctx = Context {
            items: props.items.clone(),
            input_value: match &props.input_value {
                Some(value) => Bindable::controlled(value.clone()),
                None => Bindable::uncontrolled(props.default_input_value.clone()),
            },
            visible_keys: None,
            highlighted_key: None,
            selected_key: None,
            focused: false,
            focus_visible: false,
            loading: props.loading,
            debounce_pending: false,
            disabled: props.disabled,
            filter_mode: props.filter_mode,
            collection_id,
            ids,
            locale: env.locale.clone(),
            messages: messages.clone(),
        };
        refresh_filter_and_highlight(&mut ctx, &input_value);
        let state = if props.loading {
            State::Loading
        } else {
            State::Idle
        };
        (state, ctx)
    }

    fn transition(
        state: &State,
        event: &Event,
        ctx: &Context,
        props: &Props,
    ) -> Option<TransitionPlan<Self>> {
        if ctx.disabled
            && matches!(
                event,
                Event::Focus { .. }
                    | Event::InputChange(_)
                    | Event::HighlightItem(_)
                    | Event::HighlightFirst
                    | Event::HighlightLast
                    | Event::HighlightNext
                    | Event::HighlightPrev
                    | Event::SelectItem(_)
                    | Event::SelectHighlighted
                    | Event::Clear
