            .set(HtmlAttr::Id, self.ctx.ids.part("input"))
            .set(HtmlAttr::Role, "combobox")
            .set(HtmlAttr::Type, "text")
            .set(HtmlAttr::Value, self.ctx.input_value.get().as_str())
