        drop(autocomplete.send(Event::DebounceExpired));

        assert!(!autocomplete.context().debounce_pending);
        assert_eq!(autocomplete.context().selected_key, None);
        assert_eq!(autocomplete.context().input_value.get(), "a");
    }

